starterCss:
/* Create an overlapping card stack:
   - Each card offset 30px right and 20px down from the previous
   - Back card: z-index 1, gray background
   - Middle card: z-index 2, blue background
   - Front card: z-index 3, green background
   - All cards: 150px x 100px */
.stack {
  position: relative;
  height: 160px;
  margin: 20px;
}

referenceSolutions:
.stack {
  position: relative;
  height: 160px;
  margin: 20px;
}
.card-layer {
  position: absolute;
  width: 150px;
  height: 100px;
  padding: 12px;
  border-radius: 4px;
  color: white;
  font-weight: bold;
}
.card-back {
  z-index: 1;
  background-color: rgb(128, 128, 128);
  top: 0;
  left: 0;
}
.card-middle {
  z-index: 2;
  background-color: rgb(0, 123, 255);
  top: 20px;
  left: 30px;
}
.card-front {
  z-index: 3;
  background-color: rgb(40, 167, 69);
  top: 40px;
  left: 60px;
}

